@app.route("/reset-mfa/confirm", methods=["GET", "POST"])
def reset_mfa_confirm():
    token = request.args.get("token") or (request.get_json(silent=True) or {}).get("token")
    if not token:
        return jsonify({"error": "token required"}), 400

    payload = parse_reset_token(token)
    if not payload:
        return jsonify({"error": "invalid or expired token"}), 400

    th = token_hash(token)
    cur = db().execute(
        """
        SELECT * FROM mfa_reset_tokens
        WHERE token_hash=? AND revoked_at IS NULL
        """,
        (th,),
    )
    row = cur.fetchone()
    if not row:
        return jsonify({"error": "invalid or expired token"}), 400

    exp = datetime.fromisoformat(row["expires_at"])
    if utcnow() > exp:
        return jsonify({"error": "invalid or expired token"}), 400

    if row["used_at"] is not None:
        return jsonify({"error": "token already used"}), 400

    user = get_user_by_id(int(payload["uid"]))
    if not user:
        return jsonify({"error": "invalid token"}), 400

    db().execute("UPDATE users SET mfa_enabled=0, mfa_secret=NULL WHERE id=?", (user["id"],))
    db().execute("UPDATE mfa_reset_tokens SET used_at=? WHERE id=?", (now_iso(), row["id"]))
    db().commit()

    return jsonify({"message": "MFA has been reset. You can now log in with just your password."}), 200


@app.route("/reset-mfa/revoke-all", methods=["POST"])
def revoke_all_reset_tokens():
    user = require_auth_user()
    if not user:
        return jsonify({"error": "unauthorized"}), 401
    db().execute(
        "UPDATE mfa_reset_tokens SET revoked_at=? WHERE user_id=? AND used_at IS NULL AND revoked_at IS NULL",
        (now_iso(), user["id"]),
    )
    db().commit()
    return jsonify({"message": "all pending reset tokens revoked"}), 200


